chart.options:
chart: {
  type: 'bar',
  height: 350,
  stacked: true
},
plotOptions: {
  bar: {
    horizontal: true,
    barHeight: '60%',
  },
},
dataLabels: {
  enabled: false
},
stroke: {
  width: 2,
},
title: {
  text: 'Electricity Generation by Source'
},
xaxis: {
  categories: [2019, 2020, 2021, 2022, 2023, 2024, 2025],
},
yaxis: {
  title: {
    text: undefined
  },
},
tooltip: {
  shared: false,
  y: {
    formatter: function (val) {
      return val + " TWh"
    }
  }
},
fill: {
  type: 'pattern',
  opacity: 1,
  pattern: {
    style: ['circles', 'slantedLines', 'verticalLines', 'horizontalLines'], // string or array of strings

  }
},
states: {
  hover: {
    filter: 'none'
  }
},
legend: {
  position: 'right',
  offsetY: 40
}
